var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐야, 저게……?","JPN":"なんだ、あれ……？","ENG":"Huh? What's...?","TWN":"什麼，這是……？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"잘 잤냐, 허접?","JPN":"おはよう、ヘタクソ。","ENG":"Sleep well, scurvy dog?","TWN":"早安，嘍囉？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"저기 바쁘게 뛰어다니는 녀석들은 다들 잘 잔 모양인데.","JPN":"あっちで忙しく走り回ってる奴らはよく眠れたようだな。","ENG":"Looks like all the ones running around over there slept well.","TWN":"那邊忙進忙出的傢伙似乎睡得不錯。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"흐음- 언뜻 보기에도 출항을 준비하는 배가 열 척은 넘어 보이는데?","JPN":"ふーん、パッと見て、出航する準備をしてる船が10隻は超えそうだな。","ENG":"Hmm... There seems to be over ten ships ready for departure.","TWN":"嗯嗯，看起來好像有十幾艘船準備出海？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저기 어선도 있어요. 내항에 남아 있던 배들을 있는 대로 긁어온 모양이네요.","JPN":"あそこに漁船もありますわ。内港に残っていた船をかき集めてきたようですね。","ENG":"There are also fishing ships over there. It looks as if they gathered all the ships in port.","TWN":"那邊還有一艘漁船，他們一定是把內港所有的船隻都搜刮來了。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"말도 안 돼. 분명 어제까지만 해도 다들 바다라면 질색했으면서…….","JPN":"あり得ない。昨日まではみんな海はうんざりだって言ってたくせに……","ENG":"No way. They all said they wouldn't go out to sea yesterday...","TWN":"怎麼可能，這些人明明昨天還不願意出海……"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"누구 말마따나, 다들 돈에 눈이 멀었나 보지.","JPN":"誰かの言うとおり、みんな金に目がくらんでるみたいだな。","ENG":"Just like someone said, they're all in it for the money.","TWN":"應該就是像某人說的見錢眼開吧。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"어이, 해적 놈들. 짐 싣는데 걸리적거리니까. 비켜!","JPN":"おい、海賊ども。積み込みの邪魔だ。どけ！","ENG":"Hey, pirate trash! Move! We're loading the ship. You're getting in our way!","TWN":"喂，海盜，別擋路，我們在搬運行李，閃開！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우린 보물이 가라앉기 전에 빨리 건져내러 가야 한다고.","JPN":"俺たちは宝が沈む前に早く引き揚げにいかなきゃなんねえんだよ。","ENG":"We need to get there fast before all the treasure sinks to the bottom.","TWN":"我們得趕在寶藏沉入海底之前，把它們打撈上來。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"부두가 네놈들 거냐? 줄이나 똑바로 서.","JPN":"波止場がてめえらだけのもんだと思ってんのか？　ちゃんと並べ。","ENG":"You think this port's yours, huh? Get in line.","TWN":"碼頭是你家嗎？快排好隊。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"우릴 쫓아올 셈이라면 발목 잡지나 말라고.","JPN":"俺らを追ってくるつもりなら、足手まといになるなよ。","ENG":"All you're doing is trailing us, so don't get in our way, got that?","TWN":"想要跟著我們，就不要扯後腿。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"흥, 그건 우리가 할 소리다. 이번엔 뒤통수 치지 마.","JPN":"ふん、それはこっちのセリフだ。今度は裏切るな。","ENG":"Hmph. That goes for you too. Don't double-cross us again this time.","TWN":"哼，這句話該我們說。這次休想暗算我們。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"케케케, 뒤통수 맞는 게 무서우면 그냥 여기서 포기하고 내빼시던지.","JPN":"ケケケ、裏切られんのが怖けりゃここで諦めて逃げろよ。","ENG":"Kekeke, maybe you should give up now if you're so scared of getting backstabbed.","TWN":"嘿嘿嘿，如果害怕被人暗算，那就趁早放棄，趕快離開這裡吧。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"나중에 귀찮을 일 없게 여기서 끝장을 볼까?!","JPN":"後で面倒くさくならねえように、ここで決着をつけるか！？","ENG":"How about we settle things right now, huh?!","TWN":"不如就在這裡解決他們，免得以後麻煩？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다들 준비는 잘 되어가고 있나?","JPN":"みんな、ちゃんと準備できてるか？","ENG":"How's the preparation going?","TWN":"大家都準備好了嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"생각한 것보다 미끼가 많이 모인 것 같아 다행이군.","JPN":"思ったよりオトリがたくさん集まったようで良かったな。","ENG":"Glad to see we've got plenty of bait.","TWN":"很好，看來誘餌比想像的要多呢。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"늦잖아, 보물사냥꾼. 벌써 해가 중천이라고.","JPN":"遅いだろ、トレジャーハンター。もう真っ昼間だぜ。","ENG":"You're late, treasure hunter. It's midday already.","TWN":"寶藏獵人，你怎麼這麼晚來，太陽都曬屁股咧？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"당신,\xA0심해역에서 살아 돌아왔을 정도면 안전한 항로는 꿰고 있는 거겠지?","JPN":"あんた、深海域から生きて戻れたんなら、安全な航路を知ってるんだろ？","ENG":"Hey, you've returned from the deep sea area, so you know the safest route, right?","TWN":"你既然能從深海域活著回來，那你應該知道安全航線吧？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"범람한 바다에선 비교적 안전한 편이지.","JPN":"氾濫した海では比較的安全だ。","ENG":"More or less safe across the flooded ocean, sure.","TWN":"自然會比在翻騰的海洋裡安全些。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"따라만 오라고. 선두는 우리가 설 테니.","JPN":"ついて来い。私たちが先頭に立つ。","ENG":"Just follow me. We'll take lead.","TWN":"跟著我，我替你們帶路。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"선장! 전원 출항준비 마쳤습니다!","JPN":"船長！　全員、出航準備完了です！","ENG":"Captain! We're all set for sail!","TWN":"船長！出海準備完畢！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다들 유서는 남겨 뒀나? 이번이 마지막 출항이 될지도 모르는데.","JPN":"みんな、遺書は残したか？　これが最期の出航になるかもしれない。","ENG":"Did everyone leave a will? It might be the last time we're stepping on land.","TWN":"大家準備好遺書了嗎？這也許是你們最後一次出海。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"유서랄 게 뭐 있겠습니까?","JPN":"遺書なんてないですよ。","ENG":"There's nothing much to write in our will anyway, sir.","TWN":"要遺書幹什麼？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"배와 함께 가라앉든, 크라켄한테 먹히든, 자식들은 바다 쪽으로 절하면 될 텐데요.","JPN":"船と一緒に沈もうが、クラーケンに食われようが、海に向かってお辞儀をすればいいんです。","ENG":"Whether we sink with the ship or get eaten up by Kraken, our kids just need to pay their respects to the sea.","TWN":"無論是隨船沉沒還是被克拉肯吃掉，孩子們只要朝大海磕頭就行。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_CREW","text":{"KOREA":"으하하하하!!","JPN":"アーッハハハハッ！！","ENG":"Ba hah hah hah hah!!","TWN":"哈哈哈哈！！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_LAUGH"},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 그건 그렇지.","JPN":"ハハハ！　それはそうだな。","ENG":"Gah hah hah! That's also true.","TWN":"哈哈哈！沒錯。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"자, 그럼…","JPN":"さて、と……","ENG":"All right, then...","TWN":"好吧，那麼…"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"닻을 올려라!","JPN":"錨を上げろ！","ENG":"Raise the anchor!","TWN":"起錨！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"격벽을 통과하려는 침식체가 늘고 있어. 격벽을 닫아야 해!","JPN":"隔壁を通り抜けようとする侵食体が増えてる。隔壁を閉ざさないと！","ENG":"The number of C.O.s passing through the bulwark is increasing. We need to close off the wall!","TWN":"越來越多的的侵蝕體試圖越過隔離牆，我們必須關閉隔離牆！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GUARD_FRONTBAY_B_ADMIN","text":{"KOREA":"하지만 아직 관리국의 지시가…","JPN":"でも、まだ管理局の指示が……","ENG":"But there haven't been any orders from the Administration...","TWN":"但是管理局的指令還…"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GUARD_FRONTBAY_B_ADMIN","text":{"KOREA":"이봐! 뒤 조심해!","JPN":"おい！　後ろに気をつけろ！","ENG":"Hey! Watch out!","TWN":"喂！小心後面！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"이런…!","JPN":"しまった……！","ENG":"Damn...!","TWN":"糟糕…！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"괜찮나요? 일어날 수 있겠어요?","JPN":"大丈夫ですか？　立てそうですか？","ENG":"Are you okay? Can you stand up?","TWN":"沒事吧？還能站起來嗎？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"벨라미 비서관님…?","JPN":"ベラミー秘書官……？","ENG":"Ms. Bellamy...?","TWN":"貝拉米秘書…？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"현장까지 직접 오실 줄이야. 감사합니다.","JPN":"直接現場までお越しになるとは。ありがとうございます。","ENG":"Didn't think to see you out on the field. Thank you.","TWN":"沒想到你會親自來這裡，謝謝你。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"격벽의 현재 상황은 어떻죠?","JPN":"隔壁の状況はどうですか？","ENG":"What is the current situation of the bulwark?","TWN":"隔離牆目前的狀況如何？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_FRONTBAY_NULL_ADMIN","text":{"KOREA":"좋지 않습니다.","JPN":"良くありません。","ENG":"It's not looking good.","TWN":"狀況不太好。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_FRONTBAY_NULL_ADMIN","text":{"KOREA":"전날밤 침식체 한 마리가 격벽의 틈을 발견한 뒤로, 페로몬이라도 뿌린 것처럼 놈들이 계속 쏟아지고 있어요.","JPN":"昨夜、侵食体一体が隔壁の隙間を見つけてから、フェロモンを出しているのか仲間がずっと流れ込んできています。","ENG":"After a C.O. found a crack in the wall last night, more of them are flooding in, like it sprayed some kind of pheromone.","TWN":"自從前一晚有侵蝕體發現隔離牆上的縫隙後，他們就像被噴灑費洛蒙一樣，不斷湧進來。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"지금 남은 물자로는 얼마나 버틸 수 있나요?","JPN":"今残っている物資でどのくらい持ちますか？","ENG":"How much longer can we last with the supplies at hand?","TWN":"現有的物資能撐多久？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하루도 아슬아슬합니다. 그마저 고위침식체 같은 돌발변수가 개입되면 더 짧아질 겁니다.","JPN":"一日でもギリギリです。それも、高位侵食体のような突発的変数が介入すると、もっと短くなるでしょう。","ENG":"A day, if we're lucky. Shorter if unexpected events occur, like a high-level C.O.","TWN":"大概能撐一天，但如果高階侵蝕體也介入的話，時間可能會縮短。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_FRONTBAY_NULL_ADMIN","text":{"KOREA":"게다가 격벽을 열고 닫는 데엔 적지 않은 준비시간이 필요해요.","JPN":"しかも、隔壁の開け閉めにはかなり長い準備時間が必要です。","ENG":"On top of that, we need time to open and close the bulwark.","TWN":"而且，打開和關閉隔離牆都需要很多的準備時間。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"격벽이 열린 뒤로, 얼마나 많은 헌터들이 밖으로 나갔죠?","JPN":"隔壁が開いてから、どのくらいのハンターが外に出ましたか？","ENG":"How many hunters have gone out since the bulwark opened?","TWN":"自從隔離牆開啟後，有多少獵人出去？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"함선 인빈서블에 현상금이 걸리자 많은 배가 해역으로 나갔습니다만…","JPN":"艦船インビンシブルに賞金が掛かり、多くの船が海域に出ていきましたが……","ENG":"Once they found out about the bounty on the Invincible, many ships set sail...","TWN":"在賞金的誘因下，許多船隻紛紛出海前往尋找無敵號…"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_FRONTBAY_B_ADMIN","text":{"KOREA":"선발대가 크라켄과 접촉했다는 소식 이후로는, 모두 내항에 틀어박혀서 아무도 밖으로 나오지 않고 있습니다.","JPN":"先発隊がクラーケンと接触したという知らせを聞いた後は、みな内港に閉じこもり誰も外に出ていません。","ENG":"But after hearing news of the advance party coming into contact with Kraken, the rest have stayed within the harbor and are not leaving.","TWN":"自從先鋒隊與克拉肯交手的消息傳出後，所有人都躲進內港，沒有一個人出來。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"누군가 나오려 한대도… 격벽으로 몰려든 이 침식체 군집을 뚫고 바다로 나가는 건 쉽지 않을 겁니다.","JPN":"出ようとしても……隔壁に押し寄せてきたこの侵食体の群れをくぐりぬけて海に出るのは、そう簡単ではないのです。","ENG":"Even if they try to leave... it won't be easy to break through the army of C.O.s swarming to the bulwark.","TWN":"即使有人想逃出去…要突破隔離牆上的侵蝕體群，逃到海上，也不是件容易的事。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님의 계획이 어떤 건진 모르겠지만… 이쯤에서 실패라고 판단 내려야겠군요.","JPN":"シニア様の計画がどんなものなのかは知りませんが……このあたりで失敗と判断すべきですね。","ENG":"I am not sure of our Senior's plans, but... it seems that I will have to declare it a failure.","TWN":"雖然不知道Senior的計畫是什麼…但現在看來，似乎必須宣告計畫失敗。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"애초에 프론트베이의 헌터들을 모두 끌어 모은다 해도, 크라켄을 제압한다는 일은 결코 쉽지 않을 테니까요.","JPN":"そもそもフロントベイのハンターを全員集めたとしても、クラーケンを制圧するのは決して簡単なことではないですから。","ENG":"Because even with all the hunters in Front Bay gathered, defeating Kraken will not be easy.","TWN":"就算把前灣的所有獵人都引出海，但要打倒克拉肯，可不是一件容易的事。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"…격벽의 봉쇄를 준비해주세요. 제가 돕겠어요.","JPN":"……隔壁の封鎖を準備してください。私が手伝いましょう。","ENG":"...Please prepare to shut the bulwark. I will help.","TWN":"…準備封鎖隔離牆。我也來幫忙。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"알겠습니다.","JPN":"承知しました。","ENG":"Understood.","TWN":"是。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GUARD_FRONTBAY_B_ADMIN","text":{"KOREA":"이봐. 긴급대응체계에 따라 격벽 봉쇄를 준비한다. 신호가 떨어지면 언제든 닫을 수 있도록…","JPN":"おい。緊急対応マニュアルに従い、隔壁の封鎖を準備する。合図が出たらいつでも閉じれるように……","ENG":"Hey. Following the emergency response system, we're starting the preparations for closing the bulwark. Have it ready so we can close it off as soon as we get the signal...","TWN":"喂。根據緊急行動中心的指示，準備關閉隔離牆。訊號燈一亮，隨時準備關閉…"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KEEPER_FRONTBAY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>잠시만요. 지금 막 출항하려는 배가 있습니다.</color>","JPN":"<color=#ffd34c>待ってください。今、出航しようとしている船があります。</color>","ENG":"<color=#ffd34c>Wait. There are some ships that are just about to set sail.</color>","TWN":"<color=#ffd34c>等等，有船正準備出海。</color>"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_FRONTBAY_B_ADMIN","text":{"KOREA":"…뭐?","JPN":"……何？","ENG":"...What?","TWN":"…什麼？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GUARD_FRONTBAY_B_ADMIN","text":{"KOREA":"그냥 돌려보내. 고작 몇 명이 나가려 한다고 해서 번복될 사안이 아니다.","JPN":"戻らせろ。たかが数人の出航のために、覆されるような事案ではない。","ENG":"Tell them to turn back. We can't revert the order just because a few people want to leave.","TWN":"叫他們回去。不能因為幾個人，就耽誤關閉隔離牆。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_FRONTBAY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그게… 몇 명이 아닙니다.</color>","JPN":"<color=#ffd34c>それが……数人ではありません。</color>","ENG":"<color=#ffd34c>Well, the thing is... it's not just a few.</color>","TWN":"<color=#ffd34c>不是…幾個人。</color>"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L33_1","type":"dialog","speaker":"KEEPER_FRONTBAY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>배 숫자만 어림잡아 오백이 넘어요.</color>","JPN":"<color=#ffd34c>船だけでおよそ500隻以上です。</color>","ENG":"<color=#ffd34c>The number of ships is over five hundred. And that's a rough estimate.</color>","TWN":"<color=#ffd34c>大概有五百多艘船。</color>"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GUARD_FRONTBAY_A_ADMIN","text":{"KOREA":"잠깐, 배가 얼마나 있다고?","JPN":"まて、船がどれだけあると言った？","ENG":"Wait, how many ships again?","TWN":"什麼，你說有多少艘船？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"오백이라고요?!","JPN":"500ですって！？","ENG":"Five hundred?","TWN":"五百艘？！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그 많은 인원들이 갑자기 뭣 때문에 목숨을 거는 거죠?!","JPN":"そんなに多くの人たちが、突然何のために命がけになっているのですか！？","ENG":"Why are all those people suddenly risking their lives?!","TWN":"這些人怎麼突然這麼拼命？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_FRONTBAY_A_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_FRONTBAY_B_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"끼얏호! 보물은 우리 거다!","JPN":"ヒャッホー！　宝は俺らのものだ！","ENG":"Yo-ho-ho! The treasure's ours!","TWN":"萬歲！寶藏是我們的！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_DIVE"},{"id":"L41_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"갑부가 되던 물귀신이 되던, 오늘 끝장을 보자고!","JPN":"金持ちになろうが海の亡霊になろうが、今日で決着をつけてやる！","ENG":"Whether we become filthy rich or neighbors with Davy Jones' locker, we settle this today!","TWN":"無論你是百萬富翁還是水鬼，讓我們今天就結束它吧！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_CREW","text":{"KOREA":"격벽 진입로에 침식체 다수 발견!","JPN":"隔壁の進入路にて多数の侵食体を発見！","ENG":"Multiple C.O.s detected at the bulwark entrance!","TWN":"隔離牆入口處發現大量侵蝕體！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_FRONTBAY_JACK_CREW","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"조용히 통과하긴 어렵겠군요.","JPN":"おとなしく通過することは難しそうですな。","ENG":"We won't be able to pass through quietly.","TWN":"很難直接通過。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"시작부터 발목 잡힐 순 없지.","JPN":"始めから足を引っ張られるわけにはいかない。","ENG":"We can't let them slow us down from the start.","TWN":"不能剛開始就被困住。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"뒤는 격벽의 후방지원에 맡기고 그대로 돌파한다!","JPN":"背後は隔壁の後方支援に任せて、このまま突破する！","ENG":"Leave the bulwark to its defense in the back and push through!","TWN":"後方就交給隔離牆，我們繼續前進！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"격벽에 침식체들이 붙어 있는데? 속도를 늦춰야 하지 않을까?","JPN":"隔壁に侵食体がくっついてるぞ？　スピードを落とさなくていいのか？","ENG":"There are C.O.s clinging to the wall. Shouldn't we slow down?","TWN":"有侵蝕體趴在隔離牆上，我們是不是應該減速？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"계속 밟아. 선두를 놓쳐선 안 돼.","JPN":"突き進め。先頭を取られちゃだめだ。","ENG":"Full speed ahead. We can't let anyone take the lead.","TWN":"繼續前進，我們不能落後。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"그, 그러다 녀석들 눈에 띄어서 덤벼들기라도 하면 어쩌려고?!","JPN":"そ、そんなことしてヤツらの目について、襲いかかってきたらどうするんだよ！？","ENG":"B-but what if they start attacking us?!","TWN":"要是被那些傢伙發現，撲上來攻擊我們怎麼辦？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"오, 좋은 지적이네.","JPN":"おお、いい指摘だな。","ENG":"Oh, good point.","TWN":"喔，說得好。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"어차피 덤벼들 거라면 우리가 선빵을 치자.","JPN":"どのみち襲いかかってくるなら、あたしたちが先手を打つ。","ENG":"If they're going to attack no matter what, we should strike them first.","TWN":"既然他們要攻擊我們，不如我們先下手為強。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐어?!","JPN":"はあ！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"괜찮은 생각이군.","JPN":"いいアイデアだな。","ENG":"That's not a bad idea.","TWN":"這是個好主意。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"탈리! 발포를 허가한다!","JPN":"タリー！　発砲を許可する！","ENG":"Tallie! Permission granted to fire!","TWN":"塔莉！准許你開砲！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"앗-싸! 명령 접수!","JPN":"やった～！　ご命令、お受けしました！","ENG":"Yipee! Orders received!","TWN":"太棒啦！收到！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"으헤헤헷! 전부 터트려 버려!","JPN":"うへへへっ！　全部爆発してしまいなさい！","ENG":"Ehehehe! Blow 'em all up!","TWN":"嘿嘿嘿！全都炸飛吧！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"으아아악, 뭐하는 짓이야! 다 이쪽으로 오잖아!","JPN":"うわああっ、何しやがる！　みんなこっちに来るぞ！","ENG":"AAAGH! What the hell?! They're charging toward us now!","TWN":"啊啊啊，你在做什麼！他們都往這邊來咧！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"터커, 이거 받아.","JPN":"ターカー、受け取れよっ。","ENG":"Tucker, take this.","TWN":"塔克，拿著這個。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"카메라…? 이걸로 뭘 어쩌라는 건데?","JPN":"カメラ……？　これで何をどうしろっていうんだよ。","ENG":"A camera...? What am I supposed to do with this?","TWN":"照相機？這個要做什麼？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"현상금 걸린 녀석을 잡게 될지도 모르니까, 잘 찍고 있으라고.","JPN":"賞金首を捕まえるかもしれねえから、ちゃんと撮っとけ。","ENG":"Hold it and film us. Who knows, some of these C.O.s might have a bounty on them.","TWN":"雖然不知道這些傢伙有沒有賞金，但你好好拍。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"……미치겠네, 정말.","JPN":"……なんだよ、マジか。","ENG":"...Oh, come on. You gotta be joking.","TWN":"……真是逼死我。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"}]`);export{e as default};